mapper.select:
select ea.*, e.name as examName
from `exam_announcement` ea
left join `exam` e on ea.exam_id = e.id

     and ea.title like concat('%', #{title}, '%')
     and ea.type = #{type}
     and ea.exam_id = #{examId}
     and ea.status = #{status}

order by ea.priority desc, ea.id desc

mapper.update:
update `exam_announcement`
title = #{title}, content = #{content}, type = #{type}, priority = #{priority}, exam_id = #{examId}, status = #{status},
where id = #{id}
